import{_ as e}from"./chunks/upload.HTuUCn48.js";import{_ as a}from"./chunks/editor-overview.BjX_DzOe.js";import{_ as d,o as r,c as l,ag as i}from"./chunks/framework.CvgP6Fyv.js";const o="/screenshots/preview.png",f=JSON.parse('{"title":"基本フロー","description":"","frontmatter":{},"headers":[],"relativePath":"guide/basic-flow.md","filePath":"guide/basic-flow.md"}'),s={name:"guide/basic-flow.md"};function p(c,t,h,n,m,u){return r(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="基本フロー" tabindex="-1">基本フロー <a class="header-anchor" href="#基本フロー" aria-label="Permalink to &quot;基本フロー&quot;">​</a></h1><p>Next i-Reporter は <strong>4ステップ</strong> で Excel 帳票を ConMas i-Reporter XML に変換します。</p><h2 id="全体の流れ" tabindex="-1">全体の流れ <a class="header-anchor" href="#全体の流れ" aria-label="Permalink to &quot;全体の流れ&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Excel アップロード → プレビュー確認 → AI 解析 → 編集 &amp; XML ダウンロード</span></span></code></pre></div><hr><h2 id="step-1-excel-アップロード" tabindex="-1">Step 1: Excel アップロード <a class="header-anchor" href="#step-1-excel-アップロード" aria-label="Permalink to &quot;Step 1: Excel アップロード&quot;">​</a></h2><p>トップ画面で <code>.xlsx</code> ファイルをドラッグ&amp;ドロップ、またはクリックして選択します。</p><p><img src="'+e+'" alt="アップロード画面"></p><div class="tip custom-block"><p class="custom-block-title">対応形式</p><p><code>.xlsx</code> (Excel 2007以降) のみ対応しています。<code>.xls</code> は非対応です。</p></div><hr><h2 id="step-2-プレビュー確認" tabindex="-1">Step 2: プレビュー確認 <a class="header-anchor" href="#step-2-プレビュー確認" aria-label="Permalink to &quot;Step 2: プレビュー確認&quot;">​</a></h2><p>アップロードされた Excel のシート構造がプレビュー表示されます。</p><p><img src="'+o+'" alt="プレビュー画面"></p><ul><li>セルの値、結合、スタイルが確認できます</li><li>複数シートがある場合はタブで切替可能</li><li>この段階で内容に問題がなければ「AI で解析する」ボタンを押します</li></ul><hr><h2 id="step-3-ai-解析" tabindex="-1">Step 3: AI 解析 <a class="header-anchor" href="#step-3-ai-解析" aria-label="Permalink to &quot;Step 3: AI 解析&quot;">​</a></h2><p>OpenAI GPT がセル構造を分析し、入力項目（クラスター）を自動検出します。</p><p>解析中はローディング画面が表示されます。通常 10〜30 秒で完了します。</p><p><strong>AI が検出するクラスタータイプ:</strong></p><table tabindex="0"><thead><tr><th>タイプ</th><th>説明</th><th>例</th></tr></thead><tbody><tr><td>テキスト入力</td><td>文字を入力するセル</td><td>氏名、住所、備考</td></tr><tr><td>数値入力</td><td>数値を入力するセル</td><td>温度、数量、金額</td></tr><tr><td>日付</td><td>日付を入力するセル</td><td>実施日、記入日</td></tr><tr><td>時刻</td><td>時刻を入力するセル</td><td>開始時刻、終了時刻</td></tr><tr><td>計算式</td><td>Excel 数式があるセル</td><td>合計、小計</td></tr><tr><td>選択</td><td>ドロップダウン選択</td><td>区分、ステータス</td></tr><tr><td>チェック</td><td>チェックボックス</td><td>確認済み、合否</td></tr><tr><td>画像</td><td>写真エリア</td><td>現場写真</td></tr><tr><td>手書き</td><td>署名・印鑑エリア</td><td>サイン欄</td></tr></tbody></table><hr><h2 id="step-4-編集-xml-ダウンロード" tabindex="-1">Step 4: 編集 &amp; XML ダウンロード <a class="header-anchor" href="#step-4-編集-xml-ダウンロード" aria-label="Permalink to &quot;Step 4: 編集 &amp; XML ダウンロード&quot;">​</a></h2><p>AI 解析結果がクラスターエディタに表示されます。</p><p><img src="'+a+'" alt="クラスターエディタ"></p><ul><li>左側: PDF/テーブルプレビュー上にクラスターがオーバーレイ表示</li><li>右側: 選択中クラスターのプロパティパネル</li></ul><h3 id="編集操作" tabindex="-1">編集操作 <a class="header-anchor" href="#編集操作" aria-label="Permalink to &quot;編集操作&quot;">​</a></h3><p>クラスターの位置・サイズ・タイプを自由に調整できます。詳しくは <a href="./cluster-editor.html">クラスターエディタ</a> を参照してください。</p><h3 id="xml-ダウンロード" tabindex="-1">XML ダウンロード <a class="header-anchor" href="#xml-ダウンロード" aria-label="Permalink to &quot;XML ダウンロード&quot;">​</a></h3><p>編集が完了したら「XML を生成」ボタンをクリックします。生成された XML ファイルは ConMas i-Reporter にそのままインポートできます。</p>',29)])])}const g=d(s,[["render",p]]);export{f as __pageData,g as default};
